USE DispensaryManagement;
SET FOREIGN_KEY_CHECKS=0;
-- Temporarily drop appointment date triggers for seed data
DROP TRIGGER IF EXISTS trg_check_appointment_date;
DROP TRIGGER IF EXISTS trg_update_appointment_date;



-- SuperAdmins

-- Doctors

-- Staff Employees

-- Members

-- Medicines

-- Inventory

-- Medical History

-- Appointments, Visits, Prescriptions, Billing

SET FOREIGN_KEY_CHECKS=1;

-- Recreate appointment date triggers
DELIMITER //

CREATE TRIGGER trg_check_appointment_date
BEFORE INSERT ON Appointment
FOR EACH ROW
BEGIN
    IF NEW.AppointmentDate < CURDATE() THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Appointment date cannot be in the past';
    END IF;
END//

CREATE TRIGGER trg_update_appointment_date
BEFORE UPDATE ON Appointment
FOR EACH ROW
BEGIN
    IF NEW.AppointmentDate < CURDATE() THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Appointment date cannot be in the past';
    END IF;
END//

DELIMITER ;


-- Verification counts
SELECT 'SuperAdmin' AS tbl, COUNT(*) AS cnt FROM SuperAdmin
UNION ALL SELECT 'Doctor', COUNT(*) FROM Doctor
UNION ALL SELECT 'StaffEmployee', COUNT(*) FROM StaffEmployee
UNION ALL SELECT 'Member', COUNT(*) FROM Member
UNION ALL SELECT 'Medicine', COUNT(*) FROM Medicine
UNION ALL SELECT 'Inventory', COUNT(*) FROM Inventory
UNION ALL SELECT 'MedicalHistory', COUNT(*) FROM MedicalHistory
UNION ALL SELECT 'Appointment', COUNT(*) FROM Appointment
UNION ALL SELECT 'Visit', COUNT(*) FROM Visit
UNION ALL SELECT 'Prescription', COUNT(*) FROM Prescription
UNION ALL SELECT 'PrescriptionItem', COUNT(*) FROM PrescriptionItem
UNION ALL SELECT 'BillPayment', COUNT(*) FROM BillPayment;